"use client";

import { Select as SelectRoot, type SelectProps } from "./select";
import { SelectTrigger, type SelectTriggerProps } from "./select-trigger";
import { SelectContent, type SelectContentProps } from "./select-content";
import { SelectItem, type SelectItemProps } from "./select-item";
import { SelectSearch, type SelectSearchProps } from "./select-search";
import { SelectValue, type SelectValueProps, type SelectValueDisplay, type SelectValueRenderProps } from "./select-value";
import { SelectEmpty, type SelectEmptyProps } from "./select-empty";
import { SelectTags, type SelectTagsProps } from "./select-tags";

const Select = Object.assign(SelectRoot, {
  Trigger: SelectTrigger,
  Content: SelectContent,
  Item: SelectItem,
  Search: SelectSearch,
  Value: SelectValue,
  Empty: SelectEmpty,
  Tags: SelectTags,
});

export { Select, type SelectProps };
export { SelectTrigger, type SelectTriggerProps };
export { SelectContent, type SelectContentProps };
export { SelectItem, type SelectItemProps };
export { SelectSearch, type SelectSearchProps };
export { SelectValue, type SelectValueProps, type SelectValueDisplay, type SelectValueRenderProps };
export { SelectEmpty, type SelectEmptyProps };
export { SelectTags, type SelectTagsProps };

"use client";

import { Children, isValidElement, useMemo, type AriaAttributes, type ComponentPropsWithoutRef, type ReactNode, type Ref } from "react";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { SelectContext, type SelectOptionMetadata } from "./select-context";
import { SelectItem, type SelectItemProps } from "./select-item";
import { SelectSearch } from "./select-search";
import { useSelectState } from "./use-select-state";

interface SelectBaseProps<TValue extends string = string>
  extends Omit<ComponentPropsWithoutRef<"div">, "defaultValue" | "onChange" | "id"> {
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  defaultOpen?: boolean;
  highlighted?: TValue | null;
  onHighlightChange?: (value: TValue | null) => void;
  disabled?: boolean;
  variant?: "default" | "card";
  /** Sets the width of the Select container. "full" fills the parent. */
  width?: "sm" | "md" | "lg" | "full";
  /** Name attribute for the hidden form input */
  name?: string;
  required?: boolean;
  "aria-invalid"?: AriaAttributes["aria-invalid"];
  /** Applied to the interactive combobox trigger so labels can target it. */
  id?: string;
  /** Applied to the trigger so description/error live on the combobox itself. */
  "aria-describedby"?: string;
  /** Applied to the trigger so a Field.Label can name the combobox. */
  "aria-labelledby"?: string;
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
}

interface SelectSingleProps<TValue extends string = string> extends SelectBaseProps<TValue> {
  multiple?: false;
  value?: TValue;
  onChange?: (value: TValue) => void;
  defaultValue?: TValue;
}

interface SelectMultipleProps<TValue extends string = string> extends SelectBaseProps<TValue> {
  multiple: true;
  value?: TValue[];
  onChange?: (value: TValue[]) => void;
  defaultValue?: TValue[];
}

export type SelectProps<TValue extends string = string> =
  | SelectSingleProps<TValue>
  | SelectMultipleProps<TValue>;

const widthClasses = {
  sm: "w-48",
  md: "w-64",
  lg: "w-80",
  full: "w-full",
} satisfies Record<NonNullable<SelectBaseProps["width"]>, string>;

/**
 * Combobox-style select root. Supports single and multiple selection, an
 * optional search input, and form integration via `name` / `required`
 * (a hidden native `<select>` is rendered for form submission).
 *
 * Pass `multiple` to opt into multi-select; the `value` / `defaultValue` /
 * `onChange` types switch from `string` to `string[]` accordingly.
 *
 * @example
 * ```tsx
 * <Select defaultValue="main" name="branch">
 *   <SelectTrigger>
 *     <SelectValue placeholder="Branch..." />
 *   </SelectTrigger>
 *   <SelectContent>
 *     <SelectItem value="main">main</SelectItem>
 *     <SelectItem value="develop">develop</SelectItem>
 *     <SelectItem value="feature/auth">feature/auth</SelectItem>
 *   </SelectContent>
 * </Select>
 * ```
 *
 * @example
 * ```tsx
 * const [tags, setTags] = useState<string[]>([]);
 * <Select multiple value={tags} onChange={setTags}>
 *   <SelectTrigger><SelectValue placeholder="Tags..." /></SelectTrigger>
 *   <SelectContent>
 *     <SelectItem value="bug">bug</SelectItem>
 *     <SelectItem value="feature">feature</SelectItem>
 *   </SelectContent>
 * </Select>
 * ```
 */
export function Select<TValue extends string = string>(props: SelectProps<TValue>) {
  const {
    open,
    onOpenChange,
    defaultOpen,
    value,
    onChange,
    defaultValue,
    highlighted,
    onHighlightChange,
    multiple,
    disabled = false,
    variant = "default",
    width,
    name,
    required,
    "aria-invalid": ariaInvalid,
    id: triggerIdProp,
    "aria-describedby": ariaDescribedBy,
    "aria-labelledby": ariaLabelledBy,
    children,
    className,
    ref,
    ...rootProps
  } = props;
  const openControlled = "open" in props;
  const valueControlled = "value" in props;
  const highlightedControlled = "highlighted" in props;
  const options = useMemo(() => collectSelectOptions(children), [children]);
  const searchable = useMemo(() => containsSelectSearchElement(children), [children]);

  // Public props narrow on TValue; internal state machine works with `string`/`string[]`
  // and DOM-derived data attributes. The relevant runtime values flow through unchanged.
  const stateOptions = multiple
    ? {
        open,
        openControlled,
        onOpenChange,
        defaultOpen,
        value: value as readonly string[] | undefined as string[] | undefined,
        valueControlled,
        onChange: onChange as ((value: string[]) => void) | undefined,
        defaultValue: defaultValue as readonly string[] | undefined as string[] | undefined,
        highlighted: highlighted as string | null | undefined,
        highlightedControlled,
        onHighlightChange: onHighlightChange as ((value: string | null) => void) | undefined,
        multiple: true as const,
        disabled,
        searchable,
        variant,
        ariaInvalid,
        ariaDescribedBy,
        ariaLabelledBy,
        triggerIdProp,
        required,
        options,
      }
    : {
        open,
        openControlled,
        onOpenChange,
        defaultOpen,
        value: value as string | undefined,
        valueControlled,
        onChange: onChange as ((value: string) => void) | undefined,
        defaultValue: defaultValue as string | undefined,
        highlighted: highlighted as string | null | undefined,
        highlightedControlled,
        onHighlightChange: onHighlightChange as ((value: string | null) => void) | undefined,
        multiple: false as const,
        disabled,
        searchable,
        variant,
        ariaInvalid,
        ariaDescribedBy,
        ariaLabelledBy,
        triggerIdProp,
        required,
        options,
      };

  const { contextValue, wrapperRef } = useSelectState(stateOptions);

  return (
    <SelectContext value={contextValue}>
      <div
        {...rootProps}
        ref={composeRefs(wrapperRef, ref)}
        className={cn(
          "relative",
          width && widthClasses[width],
          variant === "card" && "border border-foreground bg-background shadow-[8px_8px_0px_0px_color-mix(in_srgb,var(--border)_50%,transparent)]",
          className
        )}
      >
        {children}
        {(name || required) && (
          Array.isArray(contextValue.value)
            ? (
                <>
                  <select
                    name={name}
                    multiple
                    value={contextValue.value}
                    required={required}
                    disabled={disabled}
                    tabIndex={-1}
                    aria-hidden={true}
                    aria-label={typeof name === "string" ? name : undefined}
                    className="sr-only"
                    onChange={() => {}}
                    onInvalid={(event) => {
                      event.preventDefault();
                      contextValue.onNativeInvalid();
                    }}
                  >
                    {contextValue.value.map((v) => (
                      <option key={v} value={v}>{v}</option>
                    ))}
                  </select>
                  {required && (
                    <input
                      type="checkbox"
                      required
                      checked={contextValue.value.length > 0}
                      disabled={disabled}
                      tabIndex={-1}
                      aria-hidden={true}
                      aria-label={typeof name === "string" ? `${name} required` : undefined}
                      readOnly
                      className="sr-only"
                      onInvalid={(event) => {
                        event.preventDefault();
                        contextValue.onNativeInvalid();
                      }}
                    />
                  )}
                </>
              )
            : (
                <select
                  name={name}
                  value={contextValue.value ?? ""}
                  required={required}
                  disabled={disabled}
                  tabIndex={-1}
                  aria-hidden={true}
                  aria-label={typeof name === "string" ? name : undefined}
                  className="sr-only"
                  onChange={() => {}}
                  onInvalid={(event) => {
                    event.preventDefault();
                    contextValue.onNativeInvalid();
                  }}
                >
                  <option value="" />
                  {contextValue.value !== null && <option value={contextValue.value}>{contextValue.value}</option>}
                </select>
              )
        )}
      </div>
    </SelectContext>
  );
}

function collectSelectOptions(children: ReactNode): ReadonlyMap<string, SelectOptionMetadata> {
  const options = new Map<string, SelectOptionMetadata>();

  Children.forEach(children, (child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return;

    if (child.type === SelectItem) {
      const props = child.props as SelectItemProps;
      options.set(props.value, {
        label: props.textValue ?? getNodeText(props.children) ?? props.value,
        disabled: props.disabled ?? false,
      });
      return;
    }

    const nested = collectSelectOptions(child.props.children);
    for (const [value, metadata] of nested) options.set(value, metadata);
  });

  return options;
}

function getNodeText(node: ReactNode): string | undefined {
  if (typeof node === "string" || typeof node === "number") return String(node);
  if (Array.isArray(node)) {
    const text = node.map(getNodeText).filter(Boolean).join("");
    return text || undefined;
  }
  if (isValidElement<{ children?: ReactNode }>(node)) return getNodeText(node.props.children);
  return undefined;
}

function containsSelectSearchElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === SelectSearch) return true;
    return containsSelectSearchElement(child.props.children);
  });
}

"use client";

import { createContext, useContext, type AriaAttributes, type RefObject } from "react";

export interface SelectOptionMetadata {
  label: string;
  disabled: boolean;
}

export interface SelectContextValue {
  open: boolean;
  disabled: boolean;
  searchable: boolean;
  onOpenChange: (open: boolean) => void;
  value: string | null | string[];
  multiple: boolean;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  highlighted: string | null;
  setHighlighted: (value: string | null) => void;
  selectItem: (value: string) => void;
  options: ReadonlyMap<string, SelectOptionMetadata>;
  triggerRef: RefObject<HTMLButtonElement | null>;
  contentRef: RefObject<HTMLDivElement | null>;
  searchInputRef: RefObject<HTMLInputElement | null>;
  variant: "default" | "card";
  listboxId: string;
  triggerId: string;
  ariaInvalid: AriaAttributes["aria-invalid"] | undefined;
  ariaDescribedBy: string | undefined;
  ariaLabelledBy: string | undefined;
  required: boolean | undefined;
  onNativeInvalid: () => void;
}

export const SelectContext = createContext<SelectContextValue | undefined>(
  undefined
);

export function useSelectContext(source?: string): SelectContextValue {
  const context = useContext(SelectContext);
  if (!context) {
    throw new Error(
      `${source ?? "Select compound components"} must be used within a Select`
    );
  }
  return context;
}

export function isValueSelected(value: string | null | string[], itemValue: string): boolean {
  return Array.isArray(value) ? value.includes(itemValue) : value === itemValue;
}

export function toSelectedArray(value: string | null | string[], multiple: boolean): string[] {
  if (multiple) return Array.isArray(value) ? value : [];
  return value === null ? [] : [value as string];
}

export function toOptionId(listboxId: string, value: string): string {
  const encoded = Array.from(value, (char) => char.codePointAt(0)?.toString(36) ?? "0").join("-");
  return `${listboxId}-opt-${encoded || "empty"}`;
}

export function isActiveOptionVisible(
  options: ReadonlyMap<string, { label: string; disabled: boolean }>,
  value: string | null,
  searchQuery: string,
  matches: (label: string, query: string) => boolean,
): value is string {
  if (value === null) return false;
  const option = options.get(value);
  return !!option && !option.disabled && matches(option.label, searchQuery);
}

"use client";

import type { ComponentPropsWithRef, KeyboardEvent, ReactNode } from "react";
import { resolveAriaInvalid } from "@/lib/aria-utils";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import { useSelectContext } from "./select-context";
import { matchesSearch } from "@/lib/search";
import { isActiveOptionVisible, toOptionId } from "./select-utils";

export interface SelectTriggerProps extends Omit<ComponentPropsWithRef<"button">, "children" | "type" | "disabled" | "id"> {
  children: ReactNode;
  /** Custom handle element. Defaults to an animated Chevron. Pass `null` to hide. */
  handle?: ReactNode | null;
}

export function SelectTrigger({
  children,
  className,
  handle,
  "aria-label": ariaLabel,
  "aria-invalid": triggerAriaInvalid,
  "aria-labelledby": ariaLabelledByProp,
  "aria-describedby": ariaDescribedByProp,
  "aria-errormessage": ariaErrorMessage,
  ref,
  onClick,
  onKeyDown,
  ...props
}: SelectTriggerProps) {
  const { open, disabled, searchable, onOpenChange, triggerRef, variant, triggerId, listboxId, ariaInvalid, ariaDescribedBy, ariaLabelledBy, required, options, highlighted, searchQuery } = useSelectContext("SelectTrigger");
  const resolvedAriaInvalid = resolveAriaInvalid(ariaInvalid ?? triggerAriaInvalid);
  const activeDescendant = open && !searchable && isActiveOptionVisible(options, highlighted, searchQuery, matchesSearch)
    ? toOptionId(listboxId, highlighted)
    : undefined;
  const composedDescribedBy = [ariaDescribedByProp, ariaDescribedBy].filter(Boolean).join(" ") || undefined;
  const composedLabelledBy = ariaLabelledByProp ?? ariaLabelledBy;

  const handleKeyDown = (e: KeyboardEvent<HTMLButtonElement>) => {
    onKeyDown?.(e);
    if (e.defaultPrevented) return;
    switch (e.key) {
      case "Enter":
      case " ":
        e.preventDefault();
        onOpenChange(!open);
        break;
      case "ArrowDown":
      case "ArrowUp":
        e.preventDefault();
        if (!open) onOpenChange(true);
        break;
    }
  };

  return (
    <button
      {...props}
      ref={composeRefs(triggerRef, ref)}
      id={triggerId}
      type="button"
      role={searchable ? undefined : "combobox"}
      disabled={disabled}
      aria-label={ariaLabel ?? (composedLabelledBy ? undefined : "Select")}
      aria-labelledby={ariaLabel || !composedLabelledBy ? undefined : composedLabelledBy}
      aria-haspopup="listbox"
      aria-expanded={open}
      aria-controls={open && !searchable ? listboxId : undefined}
      aria-activedescendant={searchable ? undefined : activeDescendant}
      aria-required={required}
      aria-invalid={resolvedAriaInvalid}
      aria-describedby={composedDescribedBy}
      aria-errormessage={ariaErrorMessage}
      onClick={(event) => {
        onClick?.(event);
        if (!event.defaultPrevented) onOpenChange(!open);
      }}
      onKeyDown={handleKeyDown}
      className={cn(
        "flex items-center justify-between w-full px-3 py-2 text-sm font-mono cursor-pointer focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground",
        variant === "card"
          ? "bg-foreground text-accent-foreground border-b border-foreground font-bold text-xs uppercase tracking-wider"
          : "border border-border bg-background text-foreground hover:bg-secondary",
        className
      )}
    >
      {children}
      {handle !== null && (
        handle ?? <Chevron direction="down" size="sm" className="text-muted-foreground shrink-0" />
      )}
    </button>
  );
}

"use client";

import { Children, Fragment, cloneElement, isValidElement, useCallback, useLayoutEffect, useRef, type AriaAttributes, type ReactNode, type KeyboardEvent, type Ref } from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { useTypeaheadBuffer } from "@/hooks/use-typeahead-buffer";
import { type FloatingSide, type FloatingAlign } from "@/hooks/use-floating-position";
import { composeRefs } from "@/lib/compose-refs";
import { typeaheadSearch } from "@/lib/typeahead";
import { cn } from "@/lib/utils";
import { FloatingPanel } from "../floating-panel";
import { useSelectContext } from "./select-context";
import { matchesSearch } from "@/lib/search";
import { isActiveOptionVisible, toOptionId } from "./select-utils";
import { SelectSearch } from "./select-search";
import { SelectEmpty } from "./select-empty";
import type { SelectOptionMetadata } from "./select-context";

export interface SelectContentProps {
  children: ReactNode;
  className?: string;
  onKeyDown?: (event: KeyboardEvent) => void;
  side?: FloatingSide;
  align?: FloatingAlign;
  sideOffset?: number;
  collisionPadding?: number;
  ref?: Ref<HTMLDivElement>;
}

const SEARCH_INPUT_NAV_KEYS = new Set(["ArrowUp", "ArrowDown", "Enter"]);
type ListboxProps = {
  id: string;
  role: "listbox";
  tabIndex: -1;
  "aria-multiselectable": boolean | undefined;
  "aria-activedescendant": string | undefined;
  "aria-labelledby": string;
  "aria-required": boolean | undefined;
  "aria-invalid": AriaAttributes["aria-invalid"] | undefined;
  onKeyDown?: (event: KeyboardEvent<HTMLDivElement>) => void;
};

type SearchableListboxProps = Omit<ListboxProps, "onKeyDown">;

export function SelectContent({
  children,
  className,
  onKeyDown,
  side = "bottom",
  align = "start",
  // Tighter than FloatingPanel's default (6) so the dropdown reads as visually
  // attached to the trigger. Override per-instance via the prop.
  sideOffset = 4,
  collisionPadding = 8,
  ref,
}: SelectContentProps) {
  const {
    open,
    multiple,
    variant,
    value,
    highlighted,
    setHighlighted,
    onOpenChange,
    selectItem,
    listboxId,
    triggerId,
    searchInputRef,
    triggerRef,
    contentRef: selectContentRef,
    options,
    searchQuery,
    required,
    ariaInvalid,
  } = useSelectContext("SelectContent");
  const containerRef = useRef<HTMLDivElement>(null);
  const isDropdown = variant !== "card";
  const hasSearch = containsSelectSearchElement(children);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "option",
    wrap: true,
    highlighted,
    onHighlightChange: setHighlighted,
    onSelect: selectItem,
    enabled: open,
    scopeToContainer: true,
  });

  const readTypeaheadQuery = useTypeaheadBuffer();

  function handleTypeahead(key: string): void {
    const query = readTypeaheadQuery(key);
    if (query === null) return;

    const visibleOptions = getVisibleEnabledOptionEntries();
    if (visibleOptions.length === 0) return;

    const currentIndex = highlighted === null
      ? -1
      : visibleOptions.findIndex(([itemValue]) => itemValue === highlighted);

    const match = typeaheadSearch({
      items: visibleOptions,
      query,
      currentIndex,
      getLabel: ([, option]) => option.label,
    });

    if (match) setHighlighted(match[0]);
  }

  function getVisibleEnabledOptionEntries(): Array<[string, SelectOptionMetadata]> {
    const entries: Array<[string, SelectOptionMetadata]> = [];
    for (const [itemValue, option] of options) {
      if (!option.disabled && matchesSearch(option.label, searchQuery)) {
        entries.push([itemValue, option]);
      }
    }
    return entries;
  }

  function getVisibleEnabledOptions(): string[] {
    return getVisibleEnabledOptionEntries().map(([itemValue]) => itemValue);
  }

  function moveSearchHighlight(direction: 1 | -1): void {
    const visibleOptions = getVisibleEnabledOptions();
    if (visibleOptions.length === 0) return;

    const currentIndex = highlighted === null ? -1 : visibleOptions.indexOf(highlighted);
    const nextIndex =
      currentIndex < 0
        ? direction > 0 ? 0 : visibleOptions.length - 1
        : (currentIndex + direction + visibleOptions.length) % visibleOptions.length;
    setHighlighted(visibleOptions[nextIndex]!);
  }

  function handleSearchInputNavigation(e: KeyboardEvent): void {
    if (!SEARCH_INPUT_NAV_KEYS.has(e.key)) return;

    if (e.key === "Enter") {
      e.preventDefault();
      if (isActiveOptionVisible(options, highlighted, searchQuery, matchesSearch)) {
        selectItem(highlighted);
      }
      return;
    }

    e.preventDefault();
    moveSearchHighlight(e.key === "ArrowDown" ? 1 : -1);
  }

  const initHighlight = useCallback(() => {
    if (highlighted !== null) return;
    const selectedValues = Array.isArray(value) ? value : value === null ? [] : [value];
    const firstSelected = selectedValues[0];
    if (firstSelected !== undefined && !options.get(firstSelected)?.disabled) {
      setHighlighted(firstSelected);
      return;
    }
    for (const [itemValue, option] of options) {
      if (!option.disabled) {
        setHighlighted(itemValue);
        return;
      }
    }
  }, [highlighted, options, setHighlighted, value]);

  useLayoutEffect(() => {
    if (!open) return;
    if (!searchInputRef.current) {
      containerRef.current?.focus();
    }
    initHighlight();
  }, [initHighlight, open, searchInputRef]);

  const handleKeyDown = (e: KeyboardEvent) => {
    onKeyDown?.(e);
    if (e.defaultPrevented) return;

    if (e.key === "Escape") {
      e.preventDefault();
      onOpenChange(false);
      triggerRef.current?.focus();
      return;
    }

    if (e.key === "Tab") {
      if (highlighted !== null && !multiple) selectItem(highlighted);
      onOpenChange(false);
      return;
    }

    const isTyping = e.target === searchInputRef.current;
    if (isTyping) {
      handleSearchInputNavigation(e);
    } else {
      navKeyDown(e);
      if (!e.ctrlKey && !e.metaKey && !e.altKey) handleTypeahead(e.key);
    }
  };

  const activeDescendant = isActiveOptionVisible(options, highlighted, searchQuery, matchesSearch)
    ? toOptionId(listboxId, highlighted)
    : undefined;
  const listboxPropsBase = {
    id: listboxId,
    role: "listbox" as const,
    tabIndex: -1,
    "aria-multiselectable": multiple || undefined,
    "aria-activedescendant": !hasSearch ? activeDescendant : undefined,
    "aria-labelledby": triggerId,
    "aria-required": required,
    "aria-invalid": ariaInvalid,
  } satisfies SearchableListboxProps;
  const listboxProps = hasSearch
    ? listboxPropsBase
    : { ...listboxPropsBase, onKeyDown: handleKeyDown } satisfies ListboxProps;
  const contentBody = hasSearch
    ? <SearchableContent listboxProps={listboxProps} ref={containerRef}>{children}</SearchableContent>
    : children;

  if (!isDropdown) {
    return (
      <div
        {...(hasSearch ? { onKeyDown: handleKeyDown } : listboxProps)}
        ref={hasSearch ? composeRefs(selectContentRef, ref) : composeRefs(containerRef, selectContentRef, ref)}
        hidden={!open}
        className={cn("w-full overflow-hidden p-1 space-y-0.5 outline-none", className)}
      >
        {contentBody}
        {searchQuery && <MatchCount options={options} searchQuery={searchQuery} />}
      </div>
    );
  }

  return (
    <FloatingPanel
      {...(hasSearch ? { onKeyDown: handleKeyDown } : listboxProps)}
      open={open}
      triggerRef={triggerRef}
      side={side}
      align={align}
      sideOffset={sideOffset}
      collisionPadding={collisionPadding}
      avoidCollisions
      matchTriggerWidth
      ref={hasSearch ? composeRefs(selectContentRef, ref) : composeRefs(containerRef, selectContentRef, ref)}
      className={cn(
        "border border-border bg-background shadow-2xl rounded-sm overflow-hidden outline-none",
        className,
      )}
      style={{ width: "var(--ui-floating-trigger-width)" }}
    >
      {contentBody}
      {searchQuery && <MatchCount options={options} searchQuery={searchQuery} />}
    </FloatingPanel>
  );
}

function SearchableContent({
  children,
  listboxProps,
  ref,
}: {
  children: ReactNode;
  listboxProps: SearchableListboxProps;
  ref: Ref<HTMLDivElement>;
}) {
  const { searchChildren, optionChildren, emptyChildren } = partitionSelectSearchChildren(children);

  return (
    <>
      {searchChildren}
      <div {...listboxProps} ref={ref} className="p-1 space-y-0.5 outline-none">
        {optionChildren}
      </div>
      {emptyChildren}
    </>
  );
}

function isSelectSearchElement(child: ReactNode): boolean {
  return isValidElement(child) && child.type === SelectSearch;
}

function isSelectEmptyElement(child: ReactNode): boolean {
  return isValidElement(child) && child.type === SelectEmpty;
}

function partitionSelectSearchChildren(children: ReactNode): {
  searchChildren: ReactNode[];
  optionChildren: ReactNode[];
  emptyChildren: ReactNode[];
} {
  const searchChildren: ReactNode[] = [];
  const optionChildren: ReactNode[] = [];
  const emptyChildren: ReactNode[] = [];

  Children.forEach(children, (child) => {
    if (isSelectSearchElement(child)) {
      searchChildren.push(child);
      return;
    }

    if (isSelectEmptyElement(child)) {
      emptyChildren.push(child);
      return;
    }

    if (!isValidElement<{ children?: ReactNode }>(child) || !containsPartitionedSelectElement(child.props.children)) {
      optionChildren.push(child);
      return;
    }

    const nested = partitionSelectSearchChildren(child.props.children);
    searchChildren.push(...nested.searchChildren);
    emptyChildren.push(...nested.emptyChildren);
    if (nested.optionChildren.length === 0) return;

    if (child.type === Fragment) {
      optionChildren.push(...nested.optionChildren);
    } else {
      optionChildren.push(cloneElement(child, undefined, nested.optionChildren));
    }
  });

  return { searchChildren, optionChildren, emptyChildren };
}

function containsSelectSearchElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (isSelectSearchElement(child)) return true;
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    return containsSelectSearchElement(child.props.children);
  });
}

function containsPartitionedSelectElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (isSelectSearchElement(child) || isSelectEmptyElement(child)) return true;
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    return containsPartitionedSelectElement(child.props.children);
  });
}

function MatchCount({ options, searchQuery }: { options: ReadonlyMap<string, SelectOptionMetadata>; searchQuery: string }) {
  let count = 0;
  for (const option of options.values()) {
    if (matchesSearch(option.label, searchQuery)) count++;
  }
  return (
    <div role="status" aria-live="polite" className="sr-only">
      {count} results
    </div>
  );
}

"use client";

import { type ComponentPropsWithRef, type MouseEvent, type ReactNode } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useSelectContext } from "./select-context";
import { matchesSearch } from "@/lib/search";
import { isValueSelected, toOptionId } from "./select-utils";
import { OverflowText } from "../overflow/overflow-text";

const NBSP = "\u00a0";
const BULLET = "\u25cf";
const CHECKMARK = "\u2713";

const selectItemVariants = cva(
  "flex items-center gap-2 px-2 py-1.5 text-sm font-mono cursor-pointer",
  {
    variants: {
      state: {
        default: "text-foreground/60",
        highlighted: "bg-secondary text-foreground",
        selected: "bg-foreground text-background font-medium",
        selectedMulti: "text-foreground",
        selectedMultiHighlighted: "bg-secondary text-foreground",
      },
      variant: {
        default: "",
        card: "",
      },
    },
    compoundVariants: [
      { variant: "card", state: ["default", "selectedMulti"], class: "text-muted-foreground hover:bg-border/30" },
      { variant: "card", state: "highlighted", class: "text-muted-foreground bg-border/30" },
      { variant: "card", state: ["selected", "selectedMultiHighlighted"], class: "bg-muted-foreground text-background font-medium" },
    ],
    defaultVariants: { state: "default", variant: "default" },
  }
);

type ItemState = "default" | "highlighted" | "selected" | "selectedMulti" | "selectedMultiHighlighted";

function getItemState(isSelected: boolean, isHighlighted: boolean, multiple: boolean): ItemState {
  if (!isSelected) return isHighlighted ? "highlighted" : "default";
  if (multiple) return isHighlighted ? "selectedMultiHighlighted" : "selectedMulti";
  return "selected";
}

export type SelectItemIndicator = "auto" | "checkbox" | "radio" | "none";

export interface SelectItemProps<TValue extends string = string>
  extends Omit<ComponentPropsWithRef<"div">, "children" | "onSelect"> {
  value: TValue;
  children: ReactNode;
  disabled?: boolean;
  /** Controls the selection indicator shown before the item label.
   * - `"auto"` (default): `[x]`/`[ ]` in multiple mode, `✓` in single mode
   * - `"checkbox"`: always shows `[x]`/`[ ]`
   * - `"radio"`: shows `[ • ]`/`[ ]` radio-style
   * - `"none"`: no indicator (text-only)
   */
  indicator?: SelectItemIndicator;
  /** Text for search/typeahead matching. Defaults to children text or value. */
  textValue?: string;
}

function renderIndicator(
  mode: SelectItemIndicator,
  isSelected: boolean,
  isMultiple: boolean,
): string | null {
  if (mode === "none") return null;
  if (mode === "checkbox" || (mode === "auto" && isMultiple)) {
    return isSelected ? "[x]" : "[ ]";
  }
  if (mode === "radio") {
    return isSelected ? `[${NBSP}${BULLET}${NBSP}]` : `[${NBSP}${NBSP}${NBSP}]`;
  }
  return isSelected ? CHECKMARK : null;
}

export function SelectItem<TValue extends string = string>({
  value: itemValue,
  children,
  disabled = false,
  indicator = "auto",
  textValue,
  className,
  ref,
  onClick,
  onMouseEnter,
  ...props
}: SelectItemProps<TValue>) {
  const {
    value,
    open,
    multiple,
    highlighted,
    searchQuery,
    selectItem,
    variant,
    listboxId,
  } = useSelectContext("SelectItem");

  const label = textValue ?? (typeof children === "string" ? children : itemValue);

  const isSelected = isValueSelected(value, itemValue);

  if (!open) return null;
  if (!matchesSearch(label, searchQuery)) return null;

  const isHighlighted = !disabled && highlighted === itemValue;
  const state = getItemState(isSelected, isHighlighted, multiple);
  const indicatorText = renderIndicator(indicator, isSelected, multiple);
  const showIndicatorSlot = indicator !== "none";

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (!event.defaultPrevented && !disabled) selectItem(itemValue);
  };

  return (
    <div
      {...props}
      ref={ref}
      id={toOptionId(listboxId, itemValue)}
      role="option"
      aria-selected={isSelected}
      aria-disabled={disabled || undefined}
      data-value={itemValue}
      data-label={label}
      onClick={handleClick}
      onMouseEnter={onMouseEnter}
      className={cn(
        selectItemVariants({ state, variant }),
        disabled && "opacity-50 cursor-not-allowed",
        className,
      )}
    >
      {showIndicatorSlot && (
        <span aria-hidden="true" className={cn(
          "font-mono shrink-0 whitespace-nowrap min-w-[3ch]",
          !indicatorText && "invisible"
        )}>
          {indicatorText ?? CHECKMARK}
        </span>
      )}
      {typeof children === "string" ? (
        <OverflowText className="flex-1 min-w-0">{children}</OverflowText>
      ) : (
        // Non-string children skip OverflowText (which requires `children: string`);
        // consumers using JSX labels should ensure their items fit or wrap manually.
        <span className="flex-1 min-w-0 truncate">{children}</span>
      )}
      {variant === "card" && isHighlighted && isSelected && (
        <span aria-hidden="true" className="ml-auto text-[10px] motion-safe:animate-pulse">&lt;</span>
      )}
    </div>
  );
}

"use client";

import { useLayoutEffect } from "react";
import { cn } from "@/lib/utils";
import { matchesSearch } from "@/lib/search";
import { useSelectContext } from "./select-context";
import { isActiveOptionVisible, toOptionId } from "./select-utils";

export interface SelectSearchProps {
  placeholder?: string;
  position?: "top" | "bottom";
  className?: string;
  "aria-label"?: string;
}

function searchBorderClass(variant: string, position: string): string {
  if (variant === "card") return "border-b border-foreground";
  if (position === "top") return "border-b border-border";
  return "border-t border-border";
}

export function SelectSearch({
  placeholder = "Search...",
  position = "bottom",
  className,
  "aria-label": ariaLabel,
}: SelectSearchProps) {
  const {
    open,
    searchQuery,
    onSearchChange,
    variant,
    searchInputRef,
    ariaInvalid,
    ariaLabelledBy,
    required,
    options,
    highlighted,
    listboxId,
  } = useSelectContext("SelectSearch");
  const activeDescendant = isActiveOptionVisible(options, highlighted, searchQuery, matchesSearch)
    ? toOptionId(listboxId, highlighted)
    : undefined;

  useLayoutEffect(() => {
    if (open) searchInputRef.current?.focus();
  }, [open, searchInputRef]);

  if (!open) return null;

  return (
    <div className={cn("flex items-center gap-2 px-3 py-2", searchBorderClass(variant, position))}>
      <span className="text-foreground/50 text-sm font-mono shrink-0">
        &gt;
      </span>
      <input
        ref={searchInputRef}
        type="search"
        role="combobox"
        aria-labelledby={ariaLabelledBy || undefined}
        aria-label={ariaLabelledBy ? undefined : (ariaLabel ?? "Search options")}
        aria-controls={listboxId}
        aria-expanded={open}
        aria-activedescendant={activeDescendant}
        aria-autocomplete="list"
        aria-required={required}
        aria-invalid={ariaInvalid}
        value={searchQuery}
        onChange={(e) => onSearchChange(e.target.value)}
        placeholder={placeholder}
        className={cn(
          "text-sm bg-transparent text-foreground w-full outline-none font-mono placeholder:text-foreground/30",
          className,
        )}
      />
    </div>
  );
}

